query:
-- Check SRV client ID
SELECT id, name FROM clients WHERE name = 'SRV';

-- Check users with SRV clientId
SELECT id, email, clientId FROM users WHERE clientId = (SELECT id FROM clients WHERE name = 'SRV' LIMIT 1);

-- Check all users and their clientIds
SELECT id, email, clientId FROM users ORDER BY clientId, id;

